// The bits that not every browser know
// IE8

if(typeof String.prototype.trim !== 'function') {
  String.prototype.trim = function() {
    return this.replace(/^\s+|\s+$/g, ''); 
  }
}

// Various

if (typeof Object.create === 'undefined') {
    Object.create = function (o) { 
        function F() {} 
        F.prototype = o; 
        return new F(); 
    };
}

var isIE8 = function(){
  if ($.browser.msie) if ($.browser.version='8.0') return true;

  return false;
}



if (typeof String.prototype.getUrlParameters == 'undefined') String.prototype.getUrlParameters = function(){
  var map = {};
  var parts = this.replace(/[?#&]+([^=&]+)=([^&#]*)/gi, function(m,key,value) {
    map[key] = decodeURIComponent(value);
  });
  return map; 
};

/*String.addUrlParameter v0.2*/
if (typeof String.prototype.addUrlParameter == 'undefined') String.prototype.addUrlParameter = function(name, value){

  if (typeof value == 'undefined') value = '';
  
  var string = name + '=' + encodeURIComponent(value);

  var result = this;

  if (result.indexOf('?') != -1) result = result + '&' + string;
  else result = result + '?' + string;

  return result;
};



// get size of associative array

if (typeof Object.size == 'undefined') Object.size = function(obj) {
  var size = 0, key;
  for (key in obj) {
      if (obj.hasOwnProperty(key)) size++;
  }
  return size;
};





// Other functions

var cbox = function(options){

  $('object').css('visibility','hidden');//In case there is flash overlap

  var default_args = {
    /*'width': 600,
    'height': 300,*/
    onLoad : function(){},
    onComplete: function(){},
    transition: 'none',
    opacity: 0,
    scrolling: false
  }

  for(var index in default_args) { if(typeof options[index] == 'undefined') options[index] = default_args[index]; }

  $.fn.colorbox({
    width: options['width'],
    height: options['height'],
    html: options['html'],
    transition: options['transition'],
    opacity: options['opacity'],
    onLoad: function() { options['onLoad'](); /*$('#cboxClose').hide()*/ },
    onComplete: function(){options['onComplete']()},
    onClosed: function(){ $('object').css('visibility','visible'); /*in case there flash overlap*/}
  });

}



$.str_replace = function(strng, str_to_replace, replace_with){

  var next_index = strng.indexOf(str_to_replace);

  if(str_to_replace!=replace_with){

    while(next_index!=-1){
      strng = strng.substring(0,next_index) + replace_with + strng.substring(next_index+str_to_replace.length);
      next_index = strng.indexOf(str_to_replace);
    }
  }

  return strng;
}



//Posts the 'source' form and handles the result by executing a callback or
//calling processJsonResponse if no callback is defined
$.fn.jsonPostForm = function(e,source,target,callback){

  if(e != undefined) e.preventDefault();
  if(!(source instanceof jQuery)) source = $(source);

  var lock = $(this).lock();

  var elt = this;

  $.post(
    source.attr('action'),
    source.serialize(),
    function(data){
      if(callback==undefined) processJsonResponse({'target':target, 'data': data})
      else eval(callback)(target,data,source,elt)

      lock.remove();
    },
    "json"
  );
}




var vScroll = function(elt){
  $(elt).jScrollPane({scrollbarWidth: 11,animateTo: true, dragMinHeight: 20 });
}

$.fn.vScroll = function(options) { 

  options = $.extend({
    scrollbarWidth: 11,
    animateTo: true,
    dragMinHeight: 20
  }, options);

  $(this).jScrollPane(options);
   
};


$.fn.iScroll = function(){

  if (!document.addEventListener) return;

  document.addEventListener('touchmove', function (e) { e.preventDefault(); }, false);

  if (typeof this.attr('id') == 'undefined') this.attr('id', Math.random(0,10000));
  if (this.attr('id').length == 0) this.attr('id', Math.random(0,10000));

  this.data('iScroll', new iScroll(this.attr('id'), { scrollbarClass: 'iScrollBar' }));

};


if (typeof String.prototype.trim !== 'function') {
  String.prototype.trim = function() {
    return this.replace(/^\s+|\s+$/g, ''); 
  }
}


function extend(){
  for(var i=1; i<arguments.length; i++)
      for(var key in arguments[i])
          if(arguments[i].hasOwnProperty(key))
              arguments[0][key] = arguments[i][key];
  return arguments[0];
};


